    ConcreteCreatorA -> ConcreteProductA [label="creates", arrowhead=vee, style=dashed];
    ConcreteCreatorB -> ConcreteProductB [label="creates", arrowhead=vee, style=dashed];

    ConcreteProductA --|> Product;
    ConcreteProductB --|> Product;

